272703,0.00662916,0.02537481,0.04039676,0.03327101,-0.00879317,0.06088320,-0.02049500,-0.02484356,-0.01649807,0.09138826,-0.01729897,-0.00387058,-0.04980049,0.00117200,0.02192286,0.06019740,-0.06408145,0.01202400,-0.00162387,-0.01414779,0.00123546,-0.00148687,0.06966393,0.00666125,-0.07173410,-0.06677686,-0.02265544,0.03479536,-0.00229903,0.02426288,-0.02381977,0.02226312,-0.02827631,-0.00495305,-0.02476488,-0.02702978,0.01317590,0.01972053,0.00263608,0.11103704,0.02851720,0.01007157]',E'Streaming Reasoning Content\n\nWhen using streaming responses, reasoning content is accumulated across chunks just like regular message content:\n\n[source,java]\n----\nFlux<ChatResponse> responseFlux = chatModel.stream(\n    new Prompt("Solve this logic puzzle...")\n);\n\nStringBuilder reasoning = new StringBuilder();\nStringBuilder answer = new StringBuilder();\n\nresponseFlux.subscribe(chunk -> {\n    AssistantMessage message = chunk.getResult().getOutput();\n\n    // Accumulate reasoning if present\n    String reasoningChunk = message.getMetadata().get("reasoningContent");\n    if (reasoningChunk != null) {\n        reasoning.append(reasoningChunk);\n    }\n\n    // Accumulate the final answer\n    if (message.getContent() != null) {\n        answer.append(message.getContent());\n    }\n});\n----','{"source": "spring-ai", "version": "1.0", "language": "java", "title": "In application.yml", "section_title": "openai-chat.adoc", "url": "https://github.com/spring-projects/spring-ai/blob/main/spring-ai-docs/src/main/antora/modules/ROOT/pages/api/chat/openai-chat.adoc", "topics": "spring,ai,llm,openai,chat.adoc", "categories": "ai,java,llm,embeddings"}');
